import java.util.*;

public class Solution {
    public int[] findNumOfValidWords(String[] words, String[] puzzles) {
        Map<Integer, Integer> wordCount = new HashMap<>();
        for (String word : words) {
            int mask = 0;
            for (char c : word.toCharArray()) {
                mask |= 1 << (c - 'a');
            }
            wordCount.put(mask, wordCount.getOrDefault(mask, 0) + 1);
        }
        int[] result = new int[puzzles.length];
        for (int i = 0; i < puzzles.length; i++) {
            int mask = 0;
            for (char c : puzzles[i].substring(1).toCharArray()) {
                mask |= 1 << (c - 'a');
            }
            for (int j = 0; j < 26; j++) {
                if ((mask & (1 << j)) != 0) {
                    if (wordCount.containsKey(1 << j | (1 << puzzles[i].charAt(0) - 'a'))) {
                        result[i] += wordCount.get(1 << j | (1 << puzzles[i].charAt(0) - 'a'));
                    }
                }
            }
        }
        return result;
    }
}
